var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그림자라는 거... 꽤 맛있네. 론 리.","JPN":"シャドウって……結構おいしいね、ローン・リー。","ENG":"These Shadows... are quite tasty, Lone Lee.","TWN":"這些所謂的暗影……還挺好吃的嘛，隆利。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그러엄- 내가 말했지?","JPN":"そうだよ～だから言ったでしょう？","ENG":"See? I told you.","TWN":"當然—我早就說過了吧？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"죽은 그림자를 흡수해서 산 그림자를 해치우는 침식체라니. 무한동력이네요.","JPN":"死んだシャドウを吸収して生きたシャドウを倒す侵食体とは、まさに永久機関ですね。","ENG":"A C.O. that absorbs dead Shadows to take down living ones. That's practically an infinite power source.","TWN":"能吸收死去的暗影、再吞噬活著的暗影的侵蝕體，根本就是無限動力。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"침식체치곤 제법 귀엽기도 하고요.","JPN":"侵食体にしてはなかなかかわいらしい外見をしていますし。","ENG":"And for a C.O., she's pretty cute too.","TWN":"而且以侵蝕體來說還挺可愛的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그래? 난 저런 꼬리가 달린 건 좀 징그러운데.","JPN":"そう？　私はああいう尻尾がついてるのはちょっと気持ち悪いかな。","ENG":"Really? I think anything with a tail like that is kind of creepy.","TWN":"是嗎？我倒覺得那種長著尾巴的東西有點噁心。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그나저나...","JPN":"それより……","ENG":"Anyway...","TWN":"話說……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석 눈빛이 점점 변하고 있지 않아?","JPN":"あいつ、だんだん目つきが変わってきてない？","ENG":"Isn't her gaze starting to change?","TWN":"那傢伙的眼神好像越來越不對勁了吧？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"킥킥킥...","JPN":"キキキッ……","ENG":"Kehehe...","TWN":"嘻嘻嘻……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"이렇게 많은 힘이 있으면... 더 맛있는 것도 먹을 수 있어.","JPN":"これだけの力があれば……もっと美味しいものも食べられる。","ENG":"With this much power... I can eat something even more delicious.","TWN":"既然有這麼多力量……就能吃到更美味的東西了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꺄앗!","JPN":"きゃあっ！","ENG":"Kyaah!","TWN":"呀啊！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그 중에서도... 네가 최고로 맛있어 보여.","JPN":"その中でも……あなたがいちばん美味しそう。","ENG":"You look... the most tasty.","TWN":"尤其是……你看起來最美味。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엣, 맛있어 보인다니. 살면서 그런 말은 처음 들어봐요.","JPN":"えっ、美味しそうって。そんなこと言われたのは生まれて初めてです。","ENG":"\\"Tasty\\"? I've never been told that before in my entire life.","TWN":"欸，我這輩子還是第一次被說看起來很好吃。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배, 이럴 땐 어떻게 대답해야 하는 거죠?","JPN":"ミナ先輩、こういう時はどう答えたらいいですか？","ENG":"Mina, how am I supposed to respond to something like that?","TWN":"米娜前輩，這種時候該怎麼回啊？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"지금 그런 걸 물어볼 때가 아니잖아! 내가 처리할 테니 물러서!","JPN":"そんなこと聞いてる場合じゃないでしょ！　私が片付けるから下がって！","ENG":"This isn't the time to be asking that! I'll handle it, so get back!","TWN":"現在是問這種事的時候嗎！我來處理，你快退後！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"윽, 저도 떨쳐내고 싶은데... 힘이 너무 강해요...!","JPN":"うっ、私もそうしたいんですけど……力が強すぎます……！","ENG":"Ugh, I want to shake her off too... but she's too strong...!","TWN":"唔，我也想掙脫……可是這力道太大了……！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그럼-","JPN":"じゃあ……","ENG":"Then...","TWN":"那就—"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"잘 먹겠습니다...!","JPN":"いただきま～す……！","ENG":"Bon appetit...!","TWN":"我開動了……！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으앙, 싫어어!","JPN":"わーん、助けてええ！","ENG":"Waah, nooo!","TWN":"不要啊啊啊！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"확실히 골칫거리를 한 곳에 모아두니 처리하기 편리하군.","JPN":"確かに、厄介者を1か所に集めると処理しやすいな。","ENG":"It certainly makes things easier to handle when all the trouble is gathered in one place.","TWN":"果然，把麻煩的東西集中在一起處理起來方便多了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 그림자의 힘을 삼킨 침식체도 스승님 꿀밤은 감당하지 못하는군요.","JPN":"ハハ、シャドウの力を呑み込んだ侵食体も、師匠の拳には敵わないんですね。","ENG":"Haha, even a C.O. that swallowed a Shadow's power can't withstand Master's knuckle strike.","TWN":"哈哈，連吞下暗影力量的侵蝕體，也撐不住師父的一記爆擊啊。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐으... 놀랐다아.","JPN":"ふう……びっくりした。","ENG":"Hngh... that startled me.","TWN":"呼……嚇死我了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"앞으로도 급할 땐 제법 요긴하겠어.","JPN":"これからも急を要する時は重宝しそうだ。","ENG":"This could be quite useful in emergencies from now on.","TWN":"以後緊急時應該還挺好用的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너, 이 녀석을 잘 간수하도록.","JPN":"お前、こいつの管理はちゃんとするように。","ENG":"You, make sure to keep a close watch on this one.","TWN":"你好好看著這傢伙。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"네, 넵!","JPN":"は、はいっ！","ENG":"Y-yes, ma'am!","TWN":"是、是！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"함선이 왜 이렇게 흔들리지? 설마 터널이 무너지려는 건가?","JPN":"なんで艦船がこんなに揺れるんだろう？　まさかトンネルが崩れるんじゃないよね？","ENG":"Why is the ship shaking like this? Is the tunnel about to collapse?","TWN":"艦船怎麼這麼晃？難道隧道要塌了嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"목적지에 거의 도달했다는 뜻이야. 터널이 연결하는 두 지점의 기압차가 클수록 출입구의 바람이 거세지는 것과 비슷한 원리지.","JPN":"目的地が近いってことさ。トンネルが繋いでいる両地点の気圧差が大きくなる程、出入り口の風が強くなるのと同じ原理だよ。","ENG":"It means we're almost at our destination. It's similar to how the wind at an entrance becomes stronger when there's a large pressure difference between the two connected points.","TWN":"這代表我們已經快到目的地了。這原理就跟隧道連接的兩個地點的氣壓差距越大，出入口的風就越強一樣。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리의 목적지는... 현실과는 전혀 다른 차원의 현실이니까.","JPN":"私たちの目的地は……現実とはまったく違う次元の現実だから。","ENG":"Because our destination... is a reality from a completely different dimension than ours.","TWN":"因為我們的目的地……是與現實完全不同次元的現實。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};